  opacity: 0;
  animation: fadeIn 0.5s ease-out forwards;
}

.panel:nth-child(1) { animation-delay: 0ms; }
.panel:nth-child(2) { animation-delay: 100ms; }
.panel:nth-child(3) { animation-delay: 200ms; }
.panel:nth-child(4) { animation-delay: 300ms; }

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

/* Accessibility */
:focus-visible {
  outline: 3px solid #2563eb;
  outline-offset: 2px;
