## Code Example

```javascript
// loadAfterInteract.js
export function loadAfterInteract(importFn) {
  return new Promise((resolve, reject) => {
    const tryLoad = () => {
      const p = importFn();
      Promise.resolve(p).then(resolve, reject);
    };
    if ('requestIdleCallback' in window) {
      requestIdleCallback(tryLoad, { timeout: 1000 });
    } else {
      setTimeout(tryLoad, 0);
    }
  });
}
```

